
(function () {
  const MAIN_IMAGE = "data:image/jpeg;base64,";
  const HOTSPOTS = [{"code": "E11", "name": "Everyday monitoring", "group": "appraisal", "x": 18, "y": 30, "size": 112, "image": "data:image/jpeg;base64,", "value": "7.1%", "emotion": "Neutral / Surprise", "role": "Route", "short": "Daily checking turns heat into an observable condition.", "full": "People read weather alerts, compare today with ordinary days, and monitor whether heat is becoming unusual or risky."}, {"code": "E12", "name": "Outdoor exposure", "group": "appraisal", "x": 80, "y": 49, "size": 122, "image": "data:image/jpeg;base64,", "value": "6.5%", "emotion": "Sadness / Disgust", "role": "Route", "short": "Direct sun and exposed paving make heat immediately perceivable.", "full": "Open plazas, hard surfaces, and limited shade sharpen the bodily experience of urban heat and generate discomfort."}, {"code": "E13", "name": "Night-time heat", "group": "appraisal", "x": 88, "y": 25, "size": 104, "image": "data:image/jpeg;base64,", "value": "5.2%", "emotion": "Sadness", "role": "Backbone", "short": "Heat persists after sunset and disrupts recovery.", "full": "Night-time residual heat connects urban thermal stress with sleep loss, fatigue, and the feeling that heat cannot be escaped."}, {"code": "E21", "name": "Thermal appraisal", "group": "disruption", "x": 50, "y": 42, "size": 124, "image": "data:image/jpeg;base64,", "value": "8.0%", "emotion": "Fear / Sadness", "role": "Backbone", "short": "People judge whether a space feels tolerable, risky, or comfortable.", "full": "Thermal appraisal links microclimate conditions with subjective judgment, comparing hot exposed surfaces with cooler shaded or ventilated areas."}, {"code": "E22", "name": "Work burden", "group": "disruption", "x": 68, "y": 61, "size": 112, "image": "data:image/jpeg;base64,", "value": "6.3%", "emotion": "Sadness", "role": "Backbone", "short": "Heat increases fatigue and daily obligation.", "full": "Commuting, outdoor work, and task completion become more exhausting under heat, turning weather into a practical burden."}, {"code": "E23", "name": "Mobility burden", "group": "disruption", "x": 58, "y": 75, "size": 106, "image": "data:image/jpeg;base64,", "value": "5.8%", "emotion": "Sadness", "role": "Route", "short": "Moving through the city becomes physically costly.", "full": "Waiting, walking, cycling, and crossing exposed routes translate heat into a mobile and time-sensitive burden."}, {"code": "E24", "name": "Cooling relief", "group": "coping", "x": 34, "y": 56, "size": 116, "image": "data:image/jpeg;base64,", "value": "5.4%", "emotion": "Joy", "role": "Switch", "short": "Shade, breeze, and resting areas create moments of relief.", "full": "Cooling relief shifts heat perception from discomfort to temporary restoration through shade, airflow, planting, and sheltered spaces."}, {"code": "E31", "name": "Indoor discomfort", "group": "coping", "x": 73, "y": 31, "size": 102, "image": "data:image/jpeg;base64,", "value": "6.7%", "emotion": "Anger / Sadness", "role": "Route", "short": "Enclosed or semi-enclosed spaces may trap heat.", "full": "Indoor and semi-indoor spaces do not always provide refuge; poor ventilation and trapped heat can extend discomfort."}, {"code": "E33", "name": "Consumptive cooling", "group": "coping", "x": 27, "y": 75, "size": 108, "image": "data:image/jpeg;base64,", "value": "8.1%", "emotion": "Joy", "role": "Switch", "short": "Cold drinks and cooling services become small coping rituals.", "full": "Consumptive cooling converts heat into everyday adaptive practices such as buying cold drinks, ice cream, or seeking air-conditioned refuges."}];

  function ensureScene() {
    let section = document.getElementById("scene-attention-story");

    if (!section) {
      section = document.createElement("section");
      section.id = "scene-attention-story";
      section.className = "attention-story-section";

      section.innerHTML = `
        <div class="attention-story-shell">
          <div class="attention-story-header">
            <div>
              <div class="attention-story-kicker">Attention scene atlas</div>
              <h2 class="attention-story-title">A day in the heat</h2>
              <p class="attention-story-subtitle">
                A continuous urban scene linking exposure, disruption, and coping. Circular vignettes represent sub-attention mechanisms; hover to preview and click to inspect.
              </p>
            </div>
            <div class="attention-story-tabs" id="attentionStoryTabs">
              <button class="attention-story-tab active" data-group="all">All</button>
              <button class="attention-story-tab" data-group="appraisal">Appraisal</button>
              <button class="attention-story-tab" data-group="disruption">Disruption</button>
              <button class="attention-story-tab" data-group="coping">Coping</button>
            </div>
          </div>

          <div class="attention-story-stage" id="attentionStoryStage">
            <img src="${MAIN_IMAGE}" class="attention-story-bg" alt="">
            <div class="attention-hotspot-layer" id="attentionHotspotLayer"></div>
            <div class="attention-story-tooltip" id="attentionStoryTooltip"></div>
          </div>
        </div>

        <div class="attention-story-modal hidden" id="attentionStoryModal">
          <div class="attention-story-modal-card">
            <div class="attention-story-modal-image">
              <img id="storyModalImage" src="" alt="">
            </div>
            <div class="attention-story-modal-body">
              <button class="attention-story-close" id="attentionStoryClose">×</button>
              <div class="story-modal-code" id="storyModalCode"></div>
              <h3 class="story-modal-title" id="storyModalTitle"></h3>
              <div class="story-modal-meta" id="storyModalMeta"></div>
              <p class="story-modal-text" id="storyModalText"></p>
            </div>
          </div>
        </div>
      `;

      const target =
        document.getElementById("scene3-attention-routing") ||
        document.querySelector(".scene3-attention-routing") ||
        document.getElementById("scene2-comparison");

      if (target) target.insertAdjacentElement("afterend", section);
      else document.body.appendChild(section);
    }

    return section;
  }

  function initScene() {
    ensureScene();

    const stage = document.getElementById("attentionStoryStage");
    const layer = document.getElementById("attentionHotspotLayer");
    const tooltip = document.getElementById("attentionStoryTooltip");
    const modal = document.getElementById("attentionStoryModal");
    const closeBtn = document.getElementById("attentionStoryClose");

    const modalImage = document.getElementById("storyModalImage");
    const modalCode = document.getElementById("storyModalCode");
    const modalTitle = document.getElementById("storyModalTitle");
    const modalMeta = document.getElementById("storyModalMeta");
    const modalText = document.getElementById("storyModalText");

    if (!stage || !layer) return;

    let currentGroup = "all";

    function filteredData() {
      return HOTSPOTS.filter(item => currentGroup === "all" || item.group === currentGroup);
    }

    function renderHotspots() {
      layer.innerHTML = "";

      filteredData().forEach((item, index) => {
        const btn = document.createElement("button");
        btn.className = "attention-scene-hotspot";
        btn.style.left = item.x + "%";
        btn.style.top = item.y + "%";
        btn.style.setProperty("--spot-size", (item.size || 110) + "px");
        btn.style.setProperty("--float-dur", (7 + index * 0.55) + "s");
        btn.style.setProperty("--float-delay", (-index * 0.35) + "s");

        btn.innerHTML = `
          <img src="${item.image}" alt="">
          <span class="hotspot-code">${item.code}</span>
        `;

        btn.addEventListener("mouseenter", e => showTooltip(item, e));
        btn.addEventListener("mousemove", moveTooltip);
        btn.addEventListener("mouseleave", hideTooltip);
        btn.addEventListener("click", () => openModal(item));

        layer.appendChild(btn);
      });
    }

    function showTooltip(item, event) {
      if (!tooltip) return;
      tooltip.innerHTML = `
        <div class="code">${item.code} · ${item.group}</div>
        <div class="name">${item.name}</div>
        <div class="desc">${item.short}</div>
      `;
      tooltip.classList.add("show");
      moveTooltip(event);
    }

    function moveTooltip(event) {
      if (!tooltip || !stage) return;

      const rect = stage.getBoundingClientRect();
      const tw = tooltip.offsetWidth || 270;
      const th = tooltip.offsetHeight || 120;

      let x = event.clientX - rect.left + 18;
      let y = event.clientY - rect.top - 10;

      if (x + tw > rect.width - 18) x = event.clientX - rect.left - tw - 18;
      if (y + th > rect.height - 18) y = rect.height - th - 18;
      if (y < 18) y = 18;

      tooltip.style.left = x + "px";
      tooltip.style.top = y + "px";
    }

    function hideTooltip() {
      if (tooltip) tooltip.classList.remove("show");
    }

    function openModal(item) {
      if (!modal) return;

      modalImage.src = item.image;
      modalCode.textContent = item.code + " · " + item.group;
      modalTitle.textContent = item.name;

      modalMeta.innerHTML = `
        <span>Value ${item.value}</span>
        <span>Emotion ${item.emotion}</span>
        <span>Role ${item.role}</span>
      `;

      modalText.textContent = item.full;
      modal.classList.remove("hidden");
    }

    function closeModal() {
      if (modal) modal.classList.add("hidden");
    }

    closeBtn?.addEventListener("click", closeModal);

    modal?.addEventListener("click", e => {
      if (e.target === modal) closeModal();
    });

    document.querySelectorAll("#attentionStoryTabs .attention-story-tab").forEach(btn => {
      btn.addEventListener("click", function () {
        document.querySelectorAll("#attentionStoryTabs .attention-story-tab").forEach(b => b.classList.remove("active"));
        btn.classList.add("active");
        currentGroup = btn.dataset.group || "all";
        renderHotspots();
      });
    });

    renderHotspots();

    console.log("[Attention Story] Embedded images loaded");
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", initScene);
  } else {
    initScene();
  }

  window.addEventListener("load", initScene);
})();
